+import Yoga, {type Node as YogaNode} from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+
+type Track = {min: number; max?: number; fr?: number; auto?: boolean};
+type Placement = {column: number; columnEnd: number; row: number; rowEnd: number};
+
+const tokenizeTracks = (template: string | undefined): string[] => {
+	if (!template) return [];
+	const tracks: string[] = [];
+	let depth = 0;
+	let token = '';
+	for (const character of template.trim()) {
+		if (character === '(') depth++;
+		if (character === ')') depth--;
+		if (/\\s/.test(character) && depth === 0) {
+			if (token) tracks.push(token), (token = '');
+		} else {
+			token += character;
+		}
+	}
+	if (token) tracks.push(token);
+	return tracks;
+};
+
+const parseTrack = (value: string): Track => {
+	if (value === 'auto') return {min: 0, auto: true};
+	const fraction = /^(\\d*\\.?\\d+)fr$/.exec(value);
+	if (fraction) return {min: 0, fr: Number(fraction[1])};
+	const fixed = Number(value);
+	if (Number.isFinite(fixed)) return {min: fixed, max: fixed};
+	const minmax = /^minmax\\(\\s*(\\d*\\.?\\d+)\\s*,\\s*(\\d*\\.?\\d+)(fr)?\\s*\\)$/.exec(value);
+	if (minmax) {
+		const min = Number(minmax[1]);
+		return minmax[3]
+			? {min, fr: Number(minmax[2])}
+			: {min, max: Number(minmax[2])};
+	}
+
+	throw new Error(`Invalid grid track size: ${value}`);
+};
+
+const parsePlacement = (value: number | string | undefined): [number, number] | undefined => {
+	if (typeof value === 'number') return [value - 1, value];
+	if (!value) return undefined;
+	const match = /^(\\d+)\\s*\\/\\s*(\\d+)$/.exec(value.trim());
+	if (!match) throw new Error(`Invalid grid placement: ${value}`);
+	return [Number(match[1]) - 1, Number(match[2]) - 1];
+};
+
+const overlaps = (a: Placement, b: Placement): boolean =>
+	a.column < b.columnEnd && a.columnEnd > b.column && a.row < b.rowEnd && a.rowEnd > b.row;
+
+const placeChildren = (children: DOMElement[], columns: number): Placement[] => {
+	const placements: Placement[] = [];
+	for (const child of children) {
+		const requestedColumn = parsePlacement(child.style.gridColumn);
+		const requestedRow = parsePlacement(child.style.gridRow);
+		const columnSpan = requestedColumn ? requestedColumn[1] - requestedColumn[0] : 1;
+		const rowSpan = requestedRow ? requestedRow[1] - requestedRow[0] : 1;
+		let placement: Placement | undefined;
+
+		for (let row = requestedRow?.[0] ?? 0; !placement; row++) {
+			if (requestedRow && row !== requestedRow[0]) break;
+			for (let column = requestedColumn?.[0] ?? 0; column < columns; column++) {
+				if (requestedColumn && column !== requestedColumn[0]) break;
+				const candidate = {
+					column,
+					columnEnd: column + columnSpan,
+					row,
+					rowEnd: row + rowSpan,
+				};
+				if (candidate.columnEnd <= columns && !placements.some(existing => overlaps(existing, candidate))) {
+					placement = candidate;
+					break;
+				}
+			}
+		}
+		placements.push(placement!);
+	}
+	return placements;
+};
+
+const sizeTracks = (tracks: Track[], available: number, intrinsic: number[]): number[] => {
+	const sizes = tracks.map((track, index) => track.auto ? Math.max(track.min, intrinsic[index] ?? 0) : track.min);
+	let remaining = Math.max(0, available - sizes.reduce((sum, size) => sum + size, 0));
+	const bounded = tracks.map((track, index) => ({track, index})).filter(({track}) => track.max !== undefined && track.max > track.min);
+	for (const {track, index} of bounded) {
+		const addition = Math.min(track.max! - sizes[index], remaining / bounded.length);
+		sizes[index] += addition;
+		remaining -= addition;
+	}
+	const totalFr = tracks.reduce((sum, track) => sum + (track.fr ?? 0), 0);
+	if (totalFr > 0) {
+		for (const [index, track] of tracks.entries()) sizes[index] += remaining * (track.fr ?? 0) / totalFr;
+	}
+	return sizes;
+};
+
+const layoutGrid = (element: DOMElement): void => {
+	if (element.style.display !== 'grid' || !element.yogaNode) return;
+	const children = element.childNodes.filter((child): child is DOMElement => Boolean(child.yogaNode));
+	const columns = tokenizeTracks(element.style.gridTemplateColumns).map(parseTrack);
+	if (columns.length === 0) return;
+	const placements = placeChildren(children, columns.length);
+	const rowTemplate = tokenizeTracks(element.style.gridTemplateRows).map(parseTrack);
+	const rowCount = Math.max(rowTemplate.length, ...placements.map(placement => placement.rowEnd), 0);
+	const rows = Array.from({length: rowCount}, (_, index) => rowTemplate[index] ?? {min: 0, auto: true});
+	const columnGap = element.style.columnGap ?? element.style.gap ?? 0;
+	const rowGap = element.style.rowGap ?? element.style.gap ?? 0;
+	const layout = element.yogaNode.getComputedLayout();
+	const horizontalPadding = element.yogaNode.getComputedPadding(Yoga.EDGE_LEFT) + element.yogaNode.getComputedPadding(Yoga.EDGE_RIGHT);
+	const verticalPadding = element.yogaNode.getComputedPadding(Yoga.EDGE_TOP) + element.yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM);
+	const columnIntrinsic = columns.map((_, index) => Math.max(0, ...children.filter((_, childIndex) => placements[childIndex].column === index && placements[childIndex].columnEnd === index + 1).map(child => child.yogaNode!.getComputedLayout().width)));
+	const rowIntrinsic = rows.map((_, index) => Math.max(0, ...children.filter((_, childIndex) => placements[childIndex].row === index && placements[childIndex].rowEnd === index + 1).map(child => child.yogaNode!.getComputedLayout().height)));
+	const columnSizes = sizeTracks(columns, Math.max(0, layout.width - horizontalPadding - columnGap * Math.max(0, columns.length - 1)), columnIntrinsic);
+	const rowSizes = sizeTracks(rows, Math.max(0, layout.height - verticalPadding - rowGap * Math.max(0, rows.length - 1)), rowIntrinsic);
+
+	for (const [index, child] of children.entries()) {
+		const placement = placements[index];
+		const left = columnSizes.slice(0, placement.column).reduce((sum, size) => sum + size, 0) + columnGap * placement.column;
+		const top = rowSizes.slice(0, placement.row).reduce((sum, size) => sum + size, 0) + rowGap * placement.row;
+		const width = columnSizes.slice(placement.column, placement.columnEnd).reduce((sum, size) => sum + size, 0) + columnGap * Math.max(0, placement.columnEnd - placement.column - 1);
+		const height = rowSizes.slice(placement.row, placement.rowEnd).reduce((sum, size) => sum + size, 0) + rowGap * Math.max(0, placement.rowEnd - placement.row - 1);
+		child.yogaNode!.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		child.yogaNode!.setPosition(Yoga.EDGE_LEFT, left);
+		child.yogaNode!.setPosition(Yoga.EDGE_TOP, top);
+		child.yogaNode!.setWidth(width);
+		child.yogaNode!.setHeight(height);
+	}
+};
+
+const visit = (element: DOMElement): void => {
+	layoutGrid(element);
+	for (const child of element.childNodes) if (child.yogaNode) visit(child);
+};
+
+export const calculateLayout = (root: DOMElement, width: number): void => {
+	root.yogaNode!.setWidth(width);
+	root.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+	// The first pass measures intrinsic grid items; later passes apply their tracks.
+	for (let pass = 0; pass < 2; pass++) {
+		visit(root);
+		root.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+	}
+};
